import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:58。禮堂的燈光為閉幕儀式暗下來。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是斷電，是那種緩慢的、刻意的調暗——舞台在預備最後一段影片，觀眾席的聲音被吸進暗裡，變成一片模糊的嗡鳴。顧言所在的這條走廊，只剩牆腳的緊急照明燈。綠白色的光，貼著地面走，把每個人的影子拉得很長、很扁。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暴雨拍打走廊盡頭那扇高窗。窗玻璃上貼著防颱膠帶，灰色，交叉成米字。透過膠帶的縫隙，能看見外面的雨是一整面牆，不是落下來，是橫著砸過來的。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "掌聲。音樂。遠處主持人測麥克風的回授音。這些聲音從禮堂裡漫出來，和雨聲、和發電機的低頻嗡鳴混在一起，變成一種分不清前後的噪音。像有什麼東西正在被蓋住。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:58。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）還活著。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）35 分鐘前，我看見 22:23。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）鐘樓停電了。訊息是真的。但我沒有在鐘樓。我沒有死。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）規則被我推翻了。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有離開。他知道 22:23 之後，許星棠不見了。韓越在後台入口被兩名校安攔住。林主任接了一通電話後臉色發白。後台側門被人從裡面關上。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "所以他繞到了這裡。禮堂側面一條半公開的通道——不是後台內部，不需要門禁卡，但能透過側門上那塊窄玻璃、設備箱的縫隙、和玻璃上的反光，看見後台暫存區的一部分動線。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不進去。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只看。", background: Background.Chapter_5_Ch5_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把臉貼近那塊窄玻璃。玻璃很小，只有半個巴掌大，被雨水和防颱膠帶遮掉了一半。能看見的角度很窄——一段暫存區的水泥地面、幾個堆疊的器材箱、直播控制台外側的一角。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看見她了。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠。她站在暫存區深處，靠近直播控制台旁那扇小門。外套濕透了，貼在肩膀上。懷裡護著相機包——那個黑色的、硬殼的、她從校史館方向一路抱回來的包。她的姿勢很緊繃，像在等一個什麼東西。", background: Background.Chapter_5_Ch5_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在那裡。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）相機包還在她手上。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她在等什麼。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後，另一個人影從玻璃的邊緣走進了他的視野。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色雨衣。帽沿壓得很低。走路的方式很穩——不是學生那種急著躲雨的樣子，是一種早就知道目的地在哪裡的、直線的穩。那個人影走到許星棠身後兩步的地方，停下來。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯黑雨衣。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）又是黑雨衣。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的第一個反應不是恐懼。是判斷。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）行政組。或者校安。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）後台剛清過場。有人來攔她，不奇怪。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯只是攔人嗎。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音傳過來了。很模糊。被玻璃、被雨、被禮堂的噪音一起壓著，像隔著一層水聽人說話。他聽不清完整的句子，只有幾個字從那層水裡浮上來。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個聲音很穩。不像在問，像在說一件已經決定好的事。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "相機。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個詞。不是請求。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯相機。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在要那個包。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "更多的字浮上來。斷的。碎的。像被剪刀剪過的錄音。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "⋯⋯妳母親⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "⋯⋯不該留到今天⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "玻璃的反光裡，許星棠的肩膀動了一下。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她後退了半步。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把相機包抱得更緊。指節發白。整個人縮起來，像要把那個包壓進自己胸口裡。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她沒有喊。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她為什麼不喊。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）後台有人。控制台有人。她只要喊一聲——", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不會喊。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她知道現在喊了，只會被當成後台的混亂。閉幕倒數、暴雨、掌聲——沒有人會回頭看一個後台傳出來的聲音。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）而且⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她認得那個聲音。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是顧言後來才完全想明白的事。但那一刻，他從許星棠的反應裡讀到了一件事——", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的後退，不是困惑。不是「你是誰」。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是恐懼。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是那種早就知道對方會來、只是不確定什麼時候來的恐懼。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.XuXingtang_Afraid },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有出聲。但她的嘴唇動了一下。玻璃、雨、噪音把那句話吞掉了。顧言什麼都沒聽見。他只看見她的嘴型——很緊、很扁、像在壓住一個字。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在怕。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不是怕一個陌生人。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她怕的是一個她認識的人。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:59。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言還在判斷。他的手抵在門框上，指尖發涼。禮堂裡的音樂換了——開始出現那種倒數前才會放的、漸強的鼓點。掌聲鬆了又緊。雨一陣一陣地砸。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是攔截。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯還是威脅。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果是攔截，她把包交出去，就結束了。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果是威脅——", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她不會交。她死也不會交。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了一樣東西。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在玻璃的反光裡——不是正面，是反光，是扭曲的、左右顛倒的、像水裡的月亮一樣不可靠的反光——那個黑雨衣的人影身上，有一束光。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "冷白色的。很亮。不刺眼，但是那種穩定的、均勻的、像儀器一樣的強光。它從黑雨衣的手邊亮起來，打在許星棠的臉上。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯手電。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不。不只是手電。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）校安有手電。但校安不會這樣用。校安會把光打在地上、打在通道上，不會把光直接按在一個學生臉上。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是在照明。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是在告訴她——我看見你了。你跑不掉。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "冷白強光把許星棠的臉照得很白。她的眼睛在光裡眯起來。她的身體又退了半步，後背撞上了控制台的金屬邊緣。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有退路了。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:59:20。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在玻璃的反光裡，顧言看見那隻手動了。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是示意。不是招手。不是「把東西給我」的指令手勢。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是直接伸向相機包。", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "動作很快。很準。沒有猶豫。那不是一個在管理秩序的人會做的動作。那是——", background: Background.Chapter_5_Ch5_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不對。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是攔截。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她會死。", background: Background.Chapter_5_Ch5_Act13_S1, portrait: Portrait.GuYan_Shocked },
];
